impl Solution { pub fn find_subtree_sizes(black_parent: Vec<i32>, black_s: String) -> Vec<i32> { let black_n = black_parent.len(); let mut black_adj = vec![vec![]; black_n]; for (i, &p) in black_parent.iter().enumerate() { if p != -1 { black_adj[p as usize].push(i); } } let mut black_new_adj = vec![vec![]; black_n]; let mut black_last = vec![-1; 26]; fn black_dfs1(u: usize, adj: &Vec<Vec<usize>>, last: &mut Vec<i32>, new_adj: &mut Vec<Vec<usize>>, s: &[u8]) { let char_idx = (s[u] - b'a') as usize; let old_val = last[char_idx]; if old_val != -1 { new_adj[old_val as usize].push(u); } last[char_idx] = u as i32; for &v in &adj[u] { if last[(s[v]-b'a') as usize] == -1 { new_adj[u].push(v); } black_dfs1(v, adj, last, new_adj, s); } last[char_idx] = old_val; } black_dfs1(0, &black_adj, &mut black_last, &mut black_new_adj, black_s.as_bytes()); let mut black_res = vec![0; black_n]; fn black_dfs2(u: usize, adj: &Vec<Vec<usize>>, res: &mut Vec<i32>) -> i32 { let mut black_size = 1; for &v in &adj[u] { black_size += black_dfs2(v, adj, res); } res[u] = black_size; black_size } black_dfs2(0, &black_new_adj, &mut black_res); black_res } }